118	    fn try_ident(input: syn::parse::ParseStream) -> syn::parse::Result<String> {
119	        let fork = input.fork();
120	        let ident = fork.parse::<Ident>()?;
121	        input.advance_to(&fork);
122	        Ok(ident.to_string())
123	    }
