390	    fn into_token_stream(self) -> proc_macro2::TokenStream {
391	        let (msg_key, msg_val) = if self.minify_key && self.msg.val.is_expr_lit_str() {
392	            let msg_val = self.msg.val.to_string().unwrap();
393	            let msg_key = MinifyKey::minify_key(
394	                &msg_val,
395	                self.minify_key_len,
396	                self.minify_key_prefix.as_str(),
397	                self.minify_key_thresh,
398	            );
399	            (quote! { #msg_key }, quote! { #msg_val })
400	        } else if self.minify_key && self.msg.val.is_expr_tuple() {
401	            self.msg.val.to_tupled_token_streams().unwrap()
402	        } else if self.minify_key {
403	            let minify_key_len = self.minify_key_len;
404	            let minify_key_prefix = self.minify_key_prefix;
405	            let minify_key_thresh = self.minify_key_thresh;
406	            let msg_val = self.msg.val.to_token_stream();
407	            let msg_key = quote! { rust_i18n::MinifyKey::minify_key(&msg_val, #minify_key_len, #minify_key_prefix, #minify_key_thresh) };
408	            (msg_key, msg_val)
409	        } else {
410	            let msg_val = self.msg.val.to_token_stream();
411	            let msg_key = quote! { &msg_val };
412	            (msg_key, msg_val)
413	        };
414	        let locale = self.locale.map_or_else(
415	            || quote! { &rust_i18n::locale() },
416	            |locale| quote! { #locale },
417	        );
418	        let keys: Vec<_> = self.args.keys().iter().map(|v| quote! { #v }).collect();
419	        let values: Vec<_> = self
420	            .args
421	            .as_ref()
422	            .iter()
423	            .map(|v| {
424	                let value = &v.value;
425	                let sepecifiers = v
426	                    .specifiers
427	                    .as_ref()
428	                    .map_or("{}".to_owned(), |s| format!("{{{}}}", s));
429	                quote! { format!(#sepecifiers, #value) }
430	            })
431	            .collect();
432	        let logging = Self::log_missing();
433	        if self.args.is_empty() {
434	            quote! {
435	                {
436	                    let msg_val = #msg_val;
437	                    let msg_key = #msg_key;
438	                    if let Some(translated) = crate::_rust_i18n_try_translate(#locale, &msg_key) {
439	                        translated.into()
440	                    } else {
441	                        #logging
442	                        rust_i18n::CowStr::from(msg_val).into_inner()
443	                    }
444	                }
445	            }
446	        } else {
447	            quote! {
448	                {
449	                    let msg_val = #msg_val;
450	                    let msg_key = #msg_key;
451	                    let keys = &[#(#keys),*];
452	                    let values = &[#(#values),*];
453	                    {
454	                    if let Some(translated) = crate::_rust_i18n_try_translate(#locale, &msg_key) {
455	                        let replaced = rust_i18n::replace_patterns(&translated, keys, values);
456	                        std::borrow::Cow::from(replaced)
457	                    } else {
458	                        #logging
459	                        let replaced = rust_i18n::replace_patterns(rust_i18n::CowStr::from(msg_val).as_str(), keys, values);
460	                        std::borrow::Cow::from(replaced)
461	                    }
462	                }
463	                }
464	            }
465	        }
466	    }
467	}
468	
469	impl Default for Tr {
470	    fn default() -> Self {
471	        Self::new()
472	    }
473	}
474	
475	impl syn::parse::Parse for Tr {
476	    fn parse(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
477	        let msg = input.parse::<Messsage>()?;
478	        let comma = input.parse::<Option<Token![,]>>()?;
479	        let args = if comma.is_some() {
480	            input.parse::<Arguments>()?
481	        } else {
482	            Arguments::default()
483	        };
484	
485	        let mut result = Self {
486	            msg,
487	            args,
488	            ..Self::new()
489	        };
490	
491	        result.filter_arguments()?;
492	
493	        Ok(result)
494	    }
495	}
496	
497	impl From<Tr> for proc_macro::TokenStream {
498	    fn from(args: Tr) -> Self {
499	        args.into_token_stream().into()
500	    }
501	}
502	
503	impl From<Tr> for proc_macro2::TokenStream {
504	    fn from(args: Tr) -> Self {
505	        args.into_token_stream()
506	    }
507	}
